313→void ALFPWorldMapPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
314→{
315→	if (!bIsDragging) return;
316→
317→	FVector2D CurrentMousePos;
318→	GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
