362→void ALFPWorldMapPlayerController::MoveToNode(ALFPWorldMapNode* Node)
363→{
364→	if (!Node) return;
365→
366→	ALFPWorldMapManager* Manager = GetWorldMapManager();
367→	if (!Manager) return;
368→
369→	// 棋子移动中不允许操作
370→	if (Manager->IsPawnMoving()) return;
371→
372→	ClearReachableHighlight();
373→
374→	// 记录目标节点，移动完成后自动进入
375→	PendingEnterNode = Node;
376→
377→	// 绑定棋子移动完成回调
378→	if (ALFPWorldMapPawn* MapPawn = Manager->GetPlayerPawn())
379→	{
380→		MapPawn->OnMoveComplete.AddUniqueDynamic(this, &ALFPWorldMapPlayerController::OnPawnMoveCompleted);
381→	}
382→
383→	bool bMoved = Manager->MovePlayer(Node->NodeID);
384→	if (!bMoved)
385→	{
386→		PendingEnterNode = nullptr;
387→	}
388→}
