471→bool ALFPWorldMapManager::LoadEdgesFromCSV(const FString& FilePath)
472→{
473→	FString CSVContent;
474→	if (!FFileHelper::LoadFileToString(CSVContent, *FilePath))
475→	{
476→		UE_LOG(LogTemp, Error, TEXT("LoadEdgesFromCSV: 无法加载文件 %s"), *FilePath);
477→		return false;
478→	}
479→
480→	UDataTable* TempTable = NewObject<UDataTable>(GetTransientPackage());
481→	TempTable->RowStruct = FLFPWorldEdgeRow::StaticStruct();
482→
483→	TArray<FString> Problems = TempTable->CreateTableFromCSVString(CSVContent);
484→	if (Problems.Num() > 0)
485→	{
486→		for (const FString& Problem : Problems)
487→		{
488→			UE_LOG(LogTemp, Warning, TEXT("边 CSV 解析问题: %s"), *Problem);
489→		}
490→	}
491→
492→	TArray<FLFPWorldEdgeRow*> AllRows;
493→	TempTable->GetAllRows<FLFPWorldEdgeRow>(TEXT("LoadEdges"), AllRows);
494→
495→	for (const FLFPWorldEdgeRow* Row : AllRows)
496→	{
497→		if (!Row) continue;
498→		AddEdge(Row->FromNodeID, Row->ToNodeID, Row->TravelTurnCost);
499→	}
500→
501→	UE_LOG(LogTemp, Log, TEXT("LoadEdgesFromCSV: 加载了 %d 条边"), AllRows.Num());
502→	return true;
503→}
