544→// ============== 迷雾系统 ==============
545→
546→TSet<int32> ALFPWorldMapManager::GetNodesWithinGraphDistance(int32 StartNodeID, int32 MaxDistance) const
547→{
548→	TSet<int32> Result;
549→
550→	if (!AdjacencyList.Contains(StartNodeID)) return Result;
551→
552→	// BFS
553→	TQueue<TPair<int32, int32>> Queue; // <NodeID, Distance>
554→	TSet<int32> Visited;
555→
556→	Queue.Enqueue(TPair<int32, int32>(StartNodeID, 0));
557→	Visited.Add(StartNodeID);
558→
559→	while (!Queue.IsEmpty())
560→	{
561→		TPair<int32, int32> Current;
562→		Queue.Dequeue(Current);
563→
564→		int32 CurrentID = Current.Key;
565→		int32 CurrentDist = Current.Value;
566→
567→		Result.Add(CurrentID);
568→
569→		if (CurrentDist >= MaxDistance) continue;
570→
571→		if (const TSet<int32>* Neighbors = AdjacencyList.Find(CurrentID))
572→		{
573→			for (int32 NeighborID : *Neighbors)
574→			{
575→				if (!Visited.Contains(NeighborID))
576→				{
577→					Visited.Add(NeighborID);
578→					Queue.Enqueue(TPair<int32, int32>(NeighborID, CurrentDist + 1));
579→				}
580→			}
581→		}
582→	}
583→
584→	return Result;
585→}
586→
587→void ALFPWorldMapManager::UpdateFog()
588→{
589→	if (!PlayerState) return;
590→
591→	// 获取视野范围内的节点
592→	TSet<int32> VisibleNodes = GetNodesWithinGraphDistance(PlayerState->CurrentNodeID, FogVisionRange);
593→
594→	// 添加到永久揭露集合
595→	for (int32 NodeID : VisibleNodes)
596→	{
597→		PlayerState->RevealedNodeIDs.Add(NodeID);
598→	}
599→
600→	// 更新所有节点的视觉状态
601→	for (auto& Pair : NodeMap)
602→	{
603→		if (!Pair.Value) continue;
604→
605→		Pair.Value->bIsRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key);
606→		Pair.Value->UpdateVisualState();
607→	}
608→
609→	// 更新边的可见性（两端都揭露才可见）
610→	for (auto& Pair : EdgeMap)
611→	{
612→		if (!Pair.Value) continue;
613→
614→		bool bBothRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key.X)
615→			&& PlayerState->RevealedNodeIDs.Contains(Pair.Key.Y);
616→		Pair.Value->SetActorHiddenInGame(!bBothRevealed);
617→	}
618→}
