620→// ============== 玩家状态 ==============
621→
622→void ALFPWorldMapManager::InitializePlayer(int32 StartNodeID)
623→{
624→	if (!PlayerState)
625→	{
626→		PlayerState = NewObject<ULFPWorldMapPlayerState>(this);
627→	}
628→
629→	PlayerState->Initialize(StartNodeID);
630→
631→	// 生成或移动玩家棋子到起始节点
632→	ALFPWorldMapNode* StartNode = GetNode(StartNodeID);
633→	FVector StartLocation = StartNode ? StartNode->GetActorLocation() + FVector(0, 0, 1) : FVector::ZeroVector;
634→
635→	if (!PlayerPawn && PawnActorClass)
636→	{
637→		FActorSpawnParameters SpawnParams;
638→		SpawnParams.Owner = this;
639→		PlayerPawn = GetWorld()->SpawnActor<ALFPWorldMapPawn>(
640→			PawnActorClass, StartLocation, FRotator::ZeroRotator, SpawnParams);
641→
642→		if (PlayerPawn)
643→		{
644→			PlayerPawn->OnMoveComplete.AddDynamic(this, &ALFPWorldMapManager::OnPawnMoveComplete);
645→		}
646→	}
647→	else if (PlayerPawn)
648→	{
649→		PlayerPawn->SetLocationImmediate(StartLocation);
650→	}
651→
652→	// 初始迷雾更新
653→	UpdateFog();
654→
655→	UE_LOG(LogTemp, Log, TEXT("玩家初始化在节点 %d"), StartNodeID);
656→}
657→
658→bool ALFPWorldMapManager::MovePlayer(int32 TargetNodeID)
659→{
660→	if (!PlayerState) return false;
661→
662→	// 棋子移动中不允许再次移动
663→	if (PlayerPawn && PlayerPawn->IsMoving()) return false;
664→
665→	bool bMoved = PlayerState->MoveToNode(TargetNodeID, this);
666→
667→	if (bMoved)
668→	{
669→		ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
670→		if (!TargetNode) return true;
671→
672→		// 如果有棋子，启动移动动画，延迟迷雾更新和事件触发
673→		if (PlayerPawn)
674→		{
675→			PendingMoveTargetNodeID = TargetNodeID;
676→			FVector TargetLocation = TargetNode->GetActorLocation() + FVector(0, 0, 1);
677→			PlayerPawn->MoveToLocation(TargetLocation);
678→		}
679→		else
680→		{
681→			// 没有棋子，直接执行后续逻辑
682→			HandlePostMove(TargetNodeID);
683→		}
684→	}
685→
686→	return bMoved;
687→}
688→
689→void ALFPWorldMapManager::OnPawnMoveComplete()
690→{
691→	if (PendingMoveTargetNodeID >= 0)
692→	{
693→		int32 NodeID = PendingMoveTargetNodeID;
694→		PendingMoveTargetNodeID = -1;
695→		HandlePostMove(NodeID);
696→	}
697→}
698→
699→void ALFPWorldMapManager::HandlePostMove(int32 TargetNodeID)
700→{
701→	// 更新迷雾
702→	UpdateFog();
703→
704→	// 触发节点事件（首次进入未触发的节点）
705→	ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
706→	if (TargetNode && !TargetNode->bHasBeenTriggered)
707→	{
708→		switch (TargetNode->NodeType)
709→		{
710→		case ELFPWorldNodeType::WNT_Battle:
711→		case ELFPWorldNodeType::WNT_Event:
712→		case ELFPWorldNodeType::WNT_Boss:
713→			TargetNode->bHasBeenTriggered = true;
714→			TargetNode->UpdateVisualState();
715→			break;
716→		default:
717→			break;
718→		}
719→	}
720→
721→	// 回合压力检查
722→	if (PlayerState && PlayerState->IsPastPressureThreshold())
723→	{
724→		UE_LOG(LogTemp, Warning, TEXT("回合压力: 已超过 %d 回合阈值！当前 %d 回合"),
725→			PlayerState->TurnPressureThreshold, PlayerState->CurrentTurn);
726→	}
727→}
